const items = $input.all();

const updatedItems = items.map((item) => {
  let timestamp;
  let objectToUpdate; // Object where we will update the date

  // Check if the data is from a button press (callback_query)
  if (item.json.callback_query) {
    // Get data from the message attached to the button
    timestamp = item.json.callback_query.message.date;
    objectToUpdate = item.json.callback_query.message;
  }
  // Otherwise, check if it's a regular message
  else if (item.json.message) {
    timestamp = item.json.message.date;
    objectToUpdate = item.json.message;
  }
  // If it's an unknown data type, just return it unchanged
  else {
    return item;
  }

  // If no date was found, also return unchanged
  if (!timestamp) {
    return item;
  }

  // Convert Unix timestamp (seconds) to a Date object (milliseconds)
  const date = new Date(timestamp * 1000);

  // Format the date for Kyiv timezone into YYYY-MM-DDTHH:mm:ss format
  const formattedDate = date
    .toLocaleString('sv-SE', { timeZone: 'Europe/Kyiv' })
    .replace(' ', 'T');

  // Overwrite the original date with the formatted value in the correct object
  objectToUpdate.date = formattedDate;

  return item;
});

return updatedItems;

function getKyivDateTimeFormatted() {
  const kyivTime = new Date().toLocaleString("en-US", { timeZone: "Europe/Kyiv" });
  const kyivDate = new Date(kyivTime);

  const year = kyivDate.getFullYear();
  const month = String(kyivDate.getMonth() + 1).padStart(2, '0');
  const day = String(kyivDate.getDate()).padStart(2, '0');
  const hour = String(kyivDate.getHours()).padStart(2, '0');
  const minute = String(kyivDate.getMinutes()).padStart(2, '0');
  const second = String(kyivDate.getSeconds()).padStart(2, '0');

  return `${year}-${month}-${day}T${hour}:${minute}:${second}`;
}

return [{ json: { kyivDateTime: getKyivDateTimeFormatted() } }];

